package org.example.cpm.math;
public record Transform(Vec3d translation,Quatd rotation,Vec3d scale){ public Transform{if(translation==null||rotation==null||scale==null)throw new IllegalArgumentException("transform fields");} public static Transform identity(){return new Transform(Vec3d.ZERO,Quatd.IDENTITY,new Vec3d(1,1,1));} public Transform compose(Transform child){return new Transform(translation.add(rotation.rotate(child.translation.hadamard(scale))),rotation.multiply(child.rotation),scale.hadamard(child.scale));} public Vec3d apply(Vec3d p){return translation.add(rotation.rotate(p.hadamard(scale)));} public Mat4d matrix(){double[]q={rotation.w(),rotation.x(),rotation.y(),rotation.z()};double w=q[0],x=q[1],y=q[2],z=q[3];return new Mat4d(new double[]{(1-2*(y*y+z*z))*scale.x(),2*(x*y-z*w)*scale.y(),2*(x*z+y*w)*scale.z(),translation.x(),2*(x*y+z*w)*scale.x(),(1-2*(x*x+z*z))*scale.y(),2*(y*z-x*w)*scale.z(),translation.y(),2*(x*z-y*w)*scale.x(),2*(y*z+x*w)*scale.y(),(1-2*(x*x+y*y))*scale.z(),translation.z(),0,0,0,1});} }
